            let diff = (freq_c - freq_m).abs() as i64;
            total_diff += diff;

            // Mark both c and m as processed to prevent re-counting when we encounter m later
            processed_pairs.insert(c, true);
            processed_pairs.insert(m, true);
        }
    }

    total_diff
}
